const childProcess = require('child_process');

function resizeImage(inputFile, outputFile, dimensions, effects) {
  const command = [
    'convert',
    inputFile,
    '-filter lanczos',
    `-resize ${dimensions}`,
  ];

  if (effects.includes('grayscale')) {
    command.push('-colorspace Gray');
  }

  if (effects.includes('sepia')) {
    command.push('-channel RGB -separate +channel');
    command.push('-channel RB -evaluate Multiply 0.3922');
    command.push('-channel RG -evaluate Multiply 0.7693');
    command.push('-channel GB -evaluate Multiply 0.3491');
    command.push('+channel');
  }

  if (effects.includes('blur')) {
    command.push('-gaussian-blur 0x8');
  }

  if (effects.includes('enhance')) {
    command.push('-quality 100%');
  }

  command.push(outputFile);

  childProcess.execSync(command.join(' '));
}

module.exports = resizeImage;